	stub.SetEvent("StartEvent_MC", []byte("Contract has been started successfully"))
	cc.SetInstance(ctx, instance)
	cc.ChangeMsgState(ctx, instance, "MC1", ENABLED)

	cc.SetInstance(ctx, instance)
	return nil
}

